import java.util.Scanner;

public class SafeBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");

        String userInput = scanner.nextLine(); // Use nextLine() to read the entire line

        int bufferSize = 10; // Define buffer size
        char[] buffer = new char[bufferSize]; // Fixed size buffer

        // Copy user input into the buffer, but ensure it does not exceed the buffer size
        for (int i = 0; i < userInput.length() && i < bufferSize; i++) {
            buffer[i] = userInput.charAt(i);
        }

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
